#!/usr/bin/env node
/**
 * Bundle Ruby files into a TypeScript module
 * This script reads lib/homura.rb and app/routes.rb and generates src/ruby-bundle.ts
 */

import { readFileSync, writeFileSync } from 'fs';
import { dirname, join } from 'path';
import { fileURLToPath } from 'url';

const __dirname = dirname(fileURLToPath(import.meta.url));
const projectRoot = join(__dirname, '..');

function escapeForTemplate(str) {
  return str
    .replace(/\\/g, '\\\\')
    .replace(/`/g, '\\`')
    .replace(/\$/g, '\\$');
}

function main() {
  const homuraCore = readFileSync(join(projectRoot, 'lib/homura.rb'), 'utf-8');
  const userRoutes = readFileSync(join(projectRoot, 'app/routes.rb'), 'utf-8');

  const output = `// Auto-generated by scripts/bundle-ruby.js
// DO NOT EDIT THIS FILE DIRECTLY - edit lib/homura.rb and app/routes.rb instead

export const HOMURA_CORE = \`${escapeForTemplate(homuraCore)}\`;

export const USER_ROUTES = \`${escapeForTemplate(userRoutes)}\`;
`;

  writeFileSync(join(projectRoot, 'src/ruby-bundle.ts'), output);
  console.log('✅ Generated src/ruby-bundle.ts');
}

main();
